//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageacctest_testimport("strings""testing""github.com/hashicorp/terraform-provider-aws/internal/acctest")tTLSRSAPrivateKeyPEM(t*testing.T){t.Parallel()key:=acctest.TLSRSAPrivateKeyPEM(t,2048)if!strings.Contains(key,acctest.PEMBlockTypeRSAPrivateKey){t.Errorf("keydoesnotcontainRSAPRIVATEKEY:%s",key)}}tTLSRSAPublicKeyPEM(t*testing.T){t.Parallel()privateKey:=acctest.TLSRSAPrivateKeyPEM(t,2048)publicKey:=acctest.TLSRSAPublicKeyPEM(t,privateKey)if!strings.Contains(publicKey,acctest.PEMBlockTypePublicKey){t.Errorf("keydoesnotcontainPUBLICKEY:%s",publicKey)}}tTLSRSAX509LocallySignedCertificatePEM(t*testing.T){t.Parallel()caKey:=acctest.TLSRSAPrivateKeyPEM(t,2048)caCertificate:=acctest.TLSRSAX509SelfSignedCACertificatePEM(t,caKey)key:=acctest.TLSRSAPrivateKeyPEM(t,2048)certificate:=acctest.TLSRSAX509LocallySignedCertificatePEM(t,caKey,caCertificate,key,"example.com")if!strings.Contains(certificate,acctest.PEMBlockTypeCertificate){t.Errorf("certificatedoesnotcontainCERTIFICATE:%s",certificate)}}tTLSRSAX509SelfSignedCACertificatePEM(t*testing.T){t.Parallel()caKey:=acctest.TLSRSAPrivateKeyPEM(t,2048)caCertificate:=acctest.TLSRSAX509SelfSignedCACertificatePEM(t,caKey)if!strings.Contains(caCertificate,acctest.PEMBlockTypeCertificate){t.Errorf("CAcertificatedoesnotcontainCERTIFICATE:%s",caCertificate)}}tTLSRSAX509SelfSignedCertificatePEM(t*testing.T){t.Parallel()key:=acctest.TLSRSAPrivateKeyPEM(t,2048)certificate:=acctest.TLSRSAX509SelfSignedCertificatePEM(t,key,"example.com")if!strings.Contains(certificate,acctest.PEMBlockTypeCertificate){t.Errorf("certificatedoesnotcontainCERTIFICATE:%s",certificate)}}tTLSRSAX509CertificateRequestPEM(t*testing.T){t.Parallel()csr,key:=acctest.TLSRSAX509CertificateRequestPEM(t,2048,"example.com")if!strings.Contains(csr,acctest.PEMBlockTypeCertificateRequest){t.Errorf("certificatedoesnotcontainCERTIFICATEREQUEST:%s",csr)}if!strings.Contains(key,acctest.PEMBlockTypeRSAPrivateKey){t.Errorf("certificatedoesnotcontainRSAPRIVATEKEY:%s",key)}}tTLSECDSAPublicKeyPEM(t*testing.T){t.Parallel()privateKey:=acctest.TLSECDSAPrivateKeyPEM(t,"P-384")publicKey,_:=acctest.TLSECDSAPublicKeyPEM(t,privateKey)if!strings.Contains(publicKey,acctest.PEMBlockTypePublicKey){t.Errorf("keydoesnotcontainPUBLICKEY:%s",publicKey)}}tTLSPEMEscapeNewlines(t*testing.T){t.Parallel()input:=`ABCD12345`want:="\\nABCD\\n12345\\n"ifgot:=acctest.TLSPEMEscapeNewlines(input);got!=want{t.Errorf("got:%s\nwant:%s",got,want)}}tTLSPEMRemovePublicKeyEncapsulationBoundaries(t*testing.T){t.Parallel()input:=`-----BEGINPUBLICKEY-----ABCD12345-----ENDPUBLICKEY-----`want:="\nABCD\n12345\n\n"ifgot:=acctest.TLSPEMRemovePublicKeyEncapsulationBoundaries(input);got!=want{t.Errorf("got:%s\nwant:%s",got,want)}}tTLSPEMRemoveNewlines(t*testing.T){t.Parallel()input:=`ABCD12345`want:="ABCD12345"ifgot:=acctest.TLSPEMRemoveNewlines(input);got!=want{t.Errorf("got:%s\nwant:%s",got,want)}}